class TestDetectWriteIntent:
    def test_returns_none_for_empty_message(self):
        assert detect_write_intent("", "myskill") is None

    def test_returns_none_for_whitespace_message(self):
        assert detect_write_intent("   ", "myskill") is None

    def test_returns_none_when_skill_is_empty(self):
        assert detect_write_intent("add a customer", "") is None

    def test_returns_none_for_pure_question(self):
        assert detect_write_intent("what customers do we have?", "myskill") is None

    def test_returns_none_for_list_request(self):
        assert detect_write_intent("show me all invoices", "myskill") is None

    def test_returns_none_when_skill_md_missing(self):
        with patch("os.path.exists", return_value=False):
            result = detect_write_intent("add a new customer called Acme", "myskill")
        assert result is None

    def test_returns_none_when_get_cached_params_returns_none(self):
        with patch("os.path.exists", return_value=True), \
             patch.object(_mod, "get_cached_params", return_value=None):
            result = detect_write_intent("add a customer", "myskill")
        assert result is None

    def test_returns_none_when_actions_is_a_list(self):
        parsed = {"actions": ["add-customer", "delete-customer"]}
        with patch("os.path.exists", return_value=True), \
             patch.object(_mod, "get_cached_params", return_value=parsed):
            result = detect_write_intent("add a customer", "myskill")
        assert result is None

    def test_returns_none_when_no_write_action_matches_threshold(self):
        parsed = {"actions": {"read-customer": {"description": "read a customer"}}}
        with patch("os.path.exists", return_value=True), \
             patch.object(_mod, "get_cached_params", return_value=parsed):
            result = detect_write_intent("add a customer", "myskill")
        assert result is None

    def test_returns_action_dict_for_write_message(self):
        parsed = {
            "actions": {
                "add-customer": {
                    "description": "add a new customer record",
                    "required": [],
                    "optional": [],
                }
            }
        }
        with patch("os.path.exists", return_value=True), \
             patch.object(_mod, "get_cached_params", return_value=parsed):
            result = detect_write_intent("add a new customer called Acme", "myskill")
        assert result is not None
        assert result["action"] == "add-customer"
        assert result["meta"] == parsed["actions"]["add-customer"]

    def test_delete_verb_triggers_write_intent(self):
        parsed = {
            "actions": {
                "delete-invoice": {
                    "description": "delete an invoice",
                    "required": [],
                    "optional": [],
                }
            }
        }
        with patch("os.path.exists", return_value=True), \
             patch.object(_mod, "get_cached_params", return_value=parsed):
            result = detect_write_intent("delete the invoice", "billing")
        assert result is not None
        assert result["action"] == "delete-invoice"

    def test_picks_best_matching_action_among_multiple(self):
        parsed = {
            "actions": {
                "add-customer": {"description": "add a customer", "required": [], "optional": []},
                "add-invoice": {"description": "add an invoice", "required": [], "optional": []},
            }
        }
        with patch("os.path.exists", return_value=True), \
             patch.object(_mod, "get_cached_params", return_value=parsed):
            result = detect_write_intent("add a new customer", "myskill")
        assert result is not None
        assert result["action"] == "add-customer"


