class TestActionMatchScore:
    def test_short_action_name_no_hyphen_returns_zero(self):
        assert _action_match_score("add something", "add", {}) == 0

    def test_exact_verb_and_entity_scores_high(self):
        score = _action_match_score("add customer now", "add-customer", {})
        assert score >= 5

    def test_synonym_verb_scores(self):
        score = _action_match_score("create a new customer", "add-customer", {})
        assert score >= 2

    def test_no_verb_or_entity_match_scores_low(self):
        score = _action_match_score("list all items", "delete-invoice", {})
        assert score < 2

    def test_description_overlap_increases_score(self):
        meta_with = {"description": "submit a payment request for approval"}
        meta_without = {}
        score_with = _action_match_score("submit payment approval", "submit-payment", meta_with)
        score_without = _action_match_score("submit payment approval", "submit-payment", meta_without)
        assert score_with >= score_without

    def test_partial_entity_word_match(self):
        score = _action_match_score("update customers", "update-customer", {})
        assert score >= 1

    def test_update_synonyms(self):
        score = _action_match_score("edit the record", "update-record", {})
        assert score >= 2

    def test_cancel_synonym(self):
        score = _action_match_score("void the transaction", "cancel-transaction", {})
        assert score >= 2


