class TestExtractParamsFromMessage:
    def test_empty_meta_returns_empty_lists(self):
        resolved, unresolved = extract_params_from_message("add something", {}, {})
        assert resolved == []
        assert unresolved == []

    def test_email_extracted_from_message(self):
        meta = {"required": [{"name": "email", "type": "string"}], "optional": []}
        resolved, unresolved = extract_params_from_message(
            "add customer with email jane@example.com", meta, {}
        )
        assert any(f["field"] == "email" and f["value"] == "jane@example.com" for f in resolved)
        assert "email" not in unresolved

    def test_required_param_unresolved_when_absent(self):
        meta = {"required": [{"name": "email", "type": "string"}], "optional": []}
        resolved, unresolved = extract_params_from_message("add a customer", meta, {})
        assert "email" in unresolved
        assert not any(f["field"] == "email" for f in resolved)

    def test_required_fields_have_higher_confidence_than_optional(self):
        meta = {
            "required": [{"name": "email", "type": "string"}],
            "optional": [{"name": "phone", "type": "string"}],
        }
        resolved, _ = extract_params_from_message(
            "add customer test@example.com phone 555-1234", meta, {}
        )
        req_entry = next((f for f in resolved if f["field"] == "email"), None)
        opt_entry = next((f for f in resolved if f["field"] == "phone"), None)
        if req_entry and opt_entry:
            assert req_entry["confidence"] > opt_entry["confidence"]

    def test_optional_params_attempted(self):
        meta = {
            "required": [],
            "optional": [{"name": "email", "type": "string"}],
        }
        resolved, _ = extract_params_from_message(
            "register with hello@example.com", meta, {}
        )
        assert any(f["field"] == "email" for f in resolved)

    def test_optional_param_source_is_inference(self):
        meta = {
            "required": [],
            "optional": [{"name": "email", "type": "string"}],
        }
        resolved, _ = extract_params_from_message("add user@example.com", meta, {})
        entry = next((f for f in resolved if f["field"] == "email"), None)
        if entry:
            assert entry["source"] == "inference"

    def test_required_param_source_is_conversation(self):
        meta = {"required": [{"name": "email", "type": "string"}], "optional": []}
        resolved, _ = extract_params_from_message("add user@example.com", meta, {})
        entry = next((f for f in resolved if f["field"] == "email"), None)
        assert entry is not None
        assert entry["source"] == "conversation"

    def test_numeric_amount_extracted(self):
        meta = {"required": [{"name": "amount", "type": "decimal"}], "optional": []}
        resolved, unresolved = extract_params_from_message(
            "create invoice for $1,250.00", meta, {}
        )
        assert any(f["field"] == "amount" and "1250" in f["value"] for f in resolved)

    def test_record_id_from_context(self):
        meta = {"required": [{"name": "record_id", "type": "string"}], "optional": []}
        resolved, unresolved = extract_params_from_message(
            "update this record", meta, {"record_id": "abc-123"}
        )
        assert any(f["field"] == "record_id" and f["value"] == "abc-123" for f in resolved)
        assert "record_id" not in unresolved

    def test_optional_params_capped_at_five(self):
        optional = [{"name": f"opt{i}", "type": "string"} for i in range(10)]
        meta = {"required": [], "optional": optional}
        resolved, _ = extract_params_from_message("some message", meta, {})
        # At most 5 optional params are attempted; resolved should be <= 5
        assert len(resolved) <= 5


