class TestBuildCompositionText:
    def _parse_composition(self, text: str) -> dict:
        m = re.search(r"<composition>(.*?)</composition>", text, re.DOTALL)
        assert m is not None, "No <composition> tag found in output"
        return json.loads(m.group(1))

    def test_output_contains_composition_tags(self):
        text = build_composition_text("add-customer", "crm", [], [])
        assert "<composition>" in text
        assert "</composition>" in text

    def test_composition_json_is_valid(self):
        text = build_composition_text("add-customer", "crm", [], [])
        data = self._parse_composition(text)
        assert isinstance(data, dict)

    def test_action_and_skill_set_in_composition(self):
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", [], [])
        )
        assert data["action"] == "add-customer"
        assert data["skill"] == "crm"

    def test_summary_capitalises_action_words(self):
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", [], [])
        )
        assert data["summary"] == "Add Customer"

    def test_multi_word_entity_in_summary(self):
        data = self._parse_composition(
            build_composition_text("create-sales-order", "sales", [], [])
        )
        assert data["summary"] == "Create Sales Order"

    def test_show_full_form_true_when_more_than_three_unresolved(self):
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", [], ["a", "b", "c", "d"])
        )
        assert data["show_full_form"] is True

    def test_show_full_form_false_when_three_or_fewer_unresolved(self):
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", [], ["a", "b", "c"])
        )
        assert data["show_full_form"] is False

    def test_resolved_fields_embedded_in_composition(self):
        resolved = [
            {
                "field": "name",
                "value": "Acme Corp",
                "confidence": 0.75,
                "source": "conversation",
                "source_detail": "Extracted from message",
            }
        ]
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", resolved, [])
        )
        assert data["resolved_fields"] == resolved

    def test_unresolved_fields_embedded_in_composition(self):
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", [], ["name", "email"])
        )
        assert data["unresolved_fields"] == ["name", "email"]

    def test_confirmation_includes_field_value_when_resolved(self):
        resolved = [
            {
                "field": "name",
                "value": "Acme",
                "confidence": 0.75,
                "source": "conversation",
                "source_detail": "x",
            }
        ]
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", resolved, [])
        )
        assert "name=Acme" in data["confirmation"]

    def test_confirmation_is_just_summary_when_no_resolved(self):
        data = self._parse_composition(
            build_composition_text("delete-invoice", "billing", [], [])
        )
        assert data["confirmation"] == "Delete Invoice?"

    def test_prompt_text_asks_to_fill_when_unresolved(self):
        text = build_composition_text("add-customer", "crm", [], ["name"])
        assert "fill in the required fields" in text

    def test_prompt_text_asks_to_review_when_all_resolved(self):
        resolved = [
            {
                "field": "name",
                "value": "Acme",
                "confidence": 0.75,
                "source": "conversation",
                "source_detail": "x",
            }
        ]
        text = build_composition_text("add-customer", "crm", resolved, [])
        assert "review and confirm" in text

    def test_confirmation_truncates_to_first_three_resolved_fields(self):
        resolved = [
            {"field": f"f{i}", "value": f"v{i}", "confidence": 0.75, "source": "conversation", "source_detail": "x"}
            for i in range(5)
        ]
        data = self._parse_composition(
            build_composition_text("add-customer", "crm", resolved, [])
        )
        # Only first 3 fields appear in confirmation string
        assert "f0=v0" in data["confirmation"]
        assert "f1=v1" in data["confirmation"]
        assert "f2=v2" in data["confirmation"]
        assert "f3=v3" not in data["confirmation"]
